        long long u = edge[0];
        long long v = edge[1];
        long long w = edge[2];
        adj[u].push_back({v, w});
        adj[v].push_back({u, w});
    }

    // Sort edges by weight
    sort(edges.begin(), edges.end(), [](const vector<long long>& a, const vector<long long>& b) {
        return a[2] < b[2];
