        if (root_u != root_v) {
            union_set(root_u, root_v);
            components--;
        }

        // Check if we have achieved the required number of components
        if (components == k) {
            return w;
        }
    }

    // If we haven't found the answer yet, return 0 (no edges left)
    return 0;
